set-variable.value:
@{{
                        // Parse the Retry-After header value as an integer number of seconds
                        int seconds;
                        var raHeader = context.Response.Headers.GetValueOrDefault('Retry-After', '0');
                        if (!int.TryParse(raHeader, out seconds)) {{ seconds = 0; }}

                        // Calculate the candidate epoch time based on the Retry-After header
                        var nowEpoch = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
                        var candidateEpoch = nowEpoch + seconds;

                        // Return the minimum of the cached value and the candidate value, or the candidate
                        // if no cached value exists or the cached value is already in the past (stale).
                        // Without the staleness check, a leftover entry from an earlier run keeps the cached
                        // epoch permanently in the past and the on-error block always emits Retry-After: 0,
                        // even when the pool is actually exhausted again.
                        long cachedEpoch;
                        var cached = context.Variables.ContainsKey('cachedRetryEpoch') ? context.Variables['cachedRetryEpoch'] as string : null;
                        return (long.TryParse(cached, out cachedEpoch) && cachedEpoch > nowEpoch && cachedEpoch < candidateEpoch) ? cachedEpoch.ToString() : candidateEpoch.ToString();
                    }}

set-header.value:
@{{
                        var cached = context.Variables.ContainsKey("cachedRetryEpoch") ? context.Variables["cachedRetryEpoch"] as string : null;
                        if (string.IsNullOrEmpty(cached)) {{ return "1"; }}

                        long cachedEpoch;
                        if (!long.TryParse(cached, out cachedEpoch)) {{ return "1"; }}

                        // Add a 1-second buffer so callers that wait exactly Retry-After seconds
                        // land just after the backend's recovery instant rather than racing it.
                        // This absorbs clock skew between gateway and client and the small latency
                        // of the next inbound request, both of which would otherwise produce another
                        // 429 immediately after the wait.
                        var remaining = Math.Max(0L, cachedEpoch - DateTimeOffset.UtcNow.ToUnixTimeSeconds());
                        return (remaining + 1).ToString();
                    }}
